O(n) solution

[#include](https://leetcode.com/problems/minimum-interval-to-include-each-query) <bits/stdc++.h>
using namespace std;

int main() 
{
    int n;
    cin >> n;
    vector<int> count(n);
    vector<int> expiry(n);
    for(int i = 0; i < n; i++)
      cin >> count[i];
    for(int i = 0; i < n; i++)
      cin >> expiry[i];

    int arr[n];
    memset(arr, 0, sizeof(arr));
    for(int i = 0; i < n; i++)
    {
      arr[i] += count[i];
      if(i + expiry[i] < n)
        arr[i + expiry[i]] -= count[i];
    }

    for(int i = 1; i < n; i++)
      arr[i] += arr[i - 1];
    int ans = 0;
    for(int i = 0; i < n; i++)
      ans = max(ans, arr[i]);
    cout << ans; 
    return 0;
}

 this question can also be done by using a **sweep line** algorithm in **O(nlogn)**

  we can frame this problem in terms of an interval of the form [ start time, end time, available stone's ]

  after this we can apply normal sweep line algorithm as- 

   ```
int maxStone( vector<int>stones , vector<int>days ) 
  {

         int mod = 1e9+7 ;
         int N = stones.size(); 
         map< int , int > M ;   // sweep line algorithm 

         for( int i = 0 ; i < N ; i++ )
         {
            int a = i ; 
            int b = days[i] + a ;   // end time = start time + duration 
            int c = stones[i] ;
            M[a] += c ; 
            M[b] -= c ; 
         }

         long long mx = 0 ; 
         long long  t = 0 ; 
         for( auto [ a , b ] : M )
         {
           t += 1LL*b ; 
           mx = max ( mx , t ); 
         }
         return mx%mod  ;
  }

   ```

Swift O(n) based on @ahbinav2807

```

func countPhiloStones(_ stones:[Int], _ days:[Int])->Int
{
    var countStones = stones
    for i in 0..<stones.count{
        if i + days[i] < countStones.count
        {
            countStones[i+days[i]] -= stones[i]
        }
    }

    for i in 1..<countStones.count
    {
        countStones[i] += countStones[i-1]
    }
    return countStones.max()!
}

var stones = [4,1,2,1,2]
var days = [1,4,5,1,6]

countPhiloStones(stones, days)

